public class StaticCounter {
    static int total = 0;
    int id;
    StaticCounter() { id = ++total; }
    static int getTotal() { return total; }
    public static void main(String[] args) {
        StaticCounter a = new StaticCounter();
        StaticCounter b = new StaticCounter();
        StaticCounter c = new StaticCounter();
        System.out.println(a.id + " " + b.id + " " + c.id);
        System.out.println(StaticCounter.getTotal());
        System.out.println(a.getTotal() == c.getTotal());
    }
}
